// Example 1: Modify loft pick points to create twist effect
IFeature loftFeature = (IFeature)selMgr.GetSelectedObject6(1, -1);
ModelDoc2 model = (ModelDoc2)swApp.ActiveDoc;
ILoftFeatureData loftData = (ILoftFeatureData)loftFeature.GetDefinition();

