// Get existing pick points
Object[] pickPointData = (Object[])loftData.PickPoints;
int numberOfChains = pickPointData.GetUpperBound(0) + 1;
Object[] newChains = new Object[numberOfChains];

// Rotate last point in each chain to create twist
MathPoint[] lastChainPoints = (MathPoint[])pickPointData[numberOfChains - 1];
MathPoint prevPoint = lastChainPoints[0];

for (int i = 0; i < numberOfChains; i++) {
    MathPoint[] chainPoints = (MathPoint[])pickPointData[i];
    MathPoint tempPoint = chainPoints[0];
    chainPoints[0] = prevPoint;
    prevPoint = tempPoint;
    newChains[i] = new DispatchWrapper[chainPoints.Length];
    for (int j = 0; j < chainPoints.Length; j++) {
        ((DispatchWrapper[])newChains[i])[j] = new DispatchWrapper(chainPoints[j]);
    }
}

loftData.PickPoints = newChains;
bool modifyOk = loftFeature.ModifyDefinition(loftData, model, null);

