// For double-ended cut extrusion with different end conditions
IFeatureManager featureMgr = modelDoc.FeatureManager;
IExtrudeFeatureData2 extrudeData = (IExtrudeFeatureData2)featureMgr.CreateDefinition((int)swFeatureNameID_e.swFmCut);

// Set double-ended cut (Sd parameter in FeatureCut4)
extrudeData.BothDirections = true;  // false for single-ended

// Flip side to cut (Flip parameter)
extrudeData.FlipSideToCut = false;  // true to remove material outside profile

// Reverse direction (Dir parameter)
extrudeData.ReverseDirection = false;  // true to reverse default direction

// End Condition 1 (T1) - forward/first direction
extrudeData.SetEndCondition(true, (int)swEndConditions_e.swEndCondBlind);  
// Valid values from swEndConditions_e:
//   - swEndCondBlind (0): Blind cut to depth
//   - swEndCondThroughAll (1): Cut through entire body
//   - swEndCondThroughNext (2): Cut to next surface
//   - swEndCondUpToVertex (3): Cut to vertex [deprecated]
//   - swEndCondUpToSurface (4): Cut to surface [deprecated]
//   - swEndCondOffsetFromSurface (5): Cut with offset from surface
//   - swEndCondMidPlane (6): Cut to mid-plane
//   - swEndCondUpToBody (7): Cut to body
//   - swEndCondThroughAllBoth (9): Cut through all both directions
//   - swEndCondUpToSelection (10): Cut to selected face/plane/vertex
//   - swEndCondUpToNext (11): Cut to next

// End Condition 2 (T2) - reverse/second direction
extrudeData.SetEndCondition(false, (int)swEndConditions_e.swEndCondBlind);

// Depth 1 (D1) - forward direction depth in meters
extrudeData.SetDepth(true, 0.01);  // 10mm

// Depth 2 (D2) - reverse direction depth in meters  
extrudeData.SetDepth(false, 0.01);

// Draft angle 1 (Dchk1, Ddir1, Dang1) - forward direction
extrudeData.SetDraftWhileExtruding(true, true);  // Enable drafting
extrudeData.SetDraftOutward(true, false);  // false=inward, true=outward
extrudeData.SetDraftAngle(true, 5.0);  // Draft angle in degrees

// Draft angle 2 (Dchk2, Ddir2, Dang2) - reverse direction
extrudeData.SetDraftWhileExtruding(false, true);
extrudeData.SetDraftOutward(false, false);
extrudeData.SetDraftAngle(false, 5.0);

// Offset reverse settings (OffsetReverse1, OffsetReverse2)
extrudeData.SetReverseOffset(true, false);  // true=away from sketch, false=toward sketch
extrudeData.SetReverseOffset(false, false);

// Surface translation (TranslateSurface1, TranslateSurface2)
extrudeData.SetTranslateSurface(true, false);  // true=translate, false=true offset
extrudeData.SetTranslateSurface(false, false);

// Sheet metal normal cut (NormalCut only valid for sheet metal parts)
extrudeData.NormalCut = false;  // true for sheet metal normal cuts

// Optimize geometry for normal cuts (OptimizeGeometry only valid when NormalCut=true)
extrudeData.OptimizeGeometry = false;

// Feature scope for multibody parts (UseFeatScope parameter)
extrudeData.FeatureScope = false;  // true to affect only selected bodies

// Auto-select bodies (UseAutoSelect parameter)
extrudeData.AutoSelect = true;  // true to auto-select all affected bodies

// Assembly feature scope (AssemblyFeatureScope parameter)
extrudeData.AssemblyFeatureScope = false;  // true to scope to selected components

// Auto-select components (AutoSelectComponents parameter)
extrudeData.AutoSelectComponents = true;  // true to auto-select all affected components

// Propagate to parts (PropagateFeatureToParts parameter)
extrudeData.PropagateFeatureToParts = false;  // true to propagate assembly feature

// Start condition (T0 parameter)
extrudeData.FromType = (int)swStartConditions_e.swStartSketchPlane;  // or other swStartConditions_e values
// Valid values from swStartConditions_e:
//   - swStartSketchPlane (0): Start from sketch plane
//   - swStartSurface (1): Start from surface
//   - swStartVertex (2): Start from vertex
//   - swStartOffset (3): Start with offset

// If FromType is swStartOffset (StartOffset parameter)
extrudeData.FromOffsetDistance = 0.005;  // Offset distance in meters
extrudeData.FromOffsetReverse = false;  // Reverse offset direction

// Create the feature
IFeature cutFeature = featureMgr.CreateFeature(extrudeData);

// ignored properties for this double-ended cut use case:
// - CapEnds (thin extrude only)
// - CapThickness (thin extrude only)
// - ThinWallType (thin extrude only)
// - LinkToThickness (thin extrude only)
// - Contours (handled separately via AccessSelections)
// - GetAutoFilletCorners, GetAutoFilletRadius (thin extrude only)
// - Merge (multibody specific)
