private DispatchWrapper[] ObjectArrayToDispatchWrapperArray(object[] objects)
{
    int size = objects.GetUpperBound(0);
    DispatchWrapper[] wrapped = new DispatchWrapper[size + 1];
    for (int i = 0; i <= size; i++)
    {
        wrapped[i] = new DispatchWrapper(objects[i]);
    }
    return wrapped;
}
