// Example: Create edge draft on part geometry with propagation to tangent faces
using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

ModelDoc2 swModel = swApp.ActiveDoc;
IModelDocExtension swDocExt = swModel.Extension;
IFeatureManager featureMgr = swModel.FeatureManager;
ISelectionMgr selectionMgr = swModel.SelectionManager;

// Clear any existing selections
swModel.ClearSelection2(true);

// Pre-selections using SelectByID2 with specific marks:
// 1. Select direction reference (e.g., bottom face of part) with mark=1
swDocExt.SelectByID2("Face@[PartBody][1]", "FACE", 0, 0, 0, false, 1, null, 0);

// 2. Select edges to draft with mark=4
swDocExt.SelectByID2("Edge@[PartBody][1]", "EDGE", 0, 0, 0, true, 4, null, 0);

// 3. Create the draft feature
double angleRadians = System.Math.PI / 18.0; // 10 degrees
Feature draftFeature = featureMgr.InsertMultiFaceDraft(
    angle: angleRadians,
    flipDir: false,
    edgeDraft: true,                           // Edge draft mode
    propType: 1,                               // Propagate to tangent faces
    isStepDraft: false,
    isBodyDraft: false
);

if (draftFeature != null)
{
