// Example: Convert existing angle-distance chamfer to distance-distance chamfer
public void ModifyChamferToDistanceDistance(IFeature chamferFeature, IModelDoc2 swModel)
{
    // Get the chamfer feature definition
    IChamferFeatureData2 chamferData = (IChamferFeatureData2)chamferFeature.GetDefinition();

    // Access selections to work with geometric entities
    chamferData.AccessSelections(swModel, null);

    try
    {
        // Change type to distance-distance
        chamferData.Type = (int)swChamferType_e.swChamferDistanceDistance; // Value: 2

        // Set both distance values
        double distance1 = 0.01;  // 10mm
        double distance2 = 0.015; // 15mm

        chamferData.SetEdgeChamferDistance(0, distance1);
        chamferData.SetEdgeChamferDistance(1, distance2);

        // Set to use different distances (not equal)
        chamferData.EqualDistance = false;

        // Apply the modifications
        bool success = chamferFeature.ModifyDefinition(chamferData, swModel, null);

        if (!success)
        {
            Debug.Print("Failed to modify chamfer");
            int errorCode = chamferFeature.GetErrorCode2();
            Debug.Print("Error code: " + errorCode);
        }
    }
    catch (Exception ex)
    {
        Debug.Print("Exception: " + ex.Message);
        chamferData.ReleaseSelectionAccess();
    }
}

// Example: Equal distance distance-distance chamfer
public void ModifyChamferToEqualDistance(IFeature chamferFeature, IModelDoc2 swModel)
{
    IChamferFeatureData2 chamferData = (IChamferFeatureData2)chamferFeature.GetDefinition();
    chamferData.AccessSelections(swModel, null);

    // Convert to distance-distance with equal distances
    chamferData.Type = (int)swChamferType_e.swChamferDistanceDistance;
    chamferData.EqualDistance = true;
    chamferData.SetEdgeChamferDistance(0, 0.01); // Both sides will use this distance

    chamferFeature.ModifyDefinition(chamferData, swModel, null);
}
