circData.EqualSpacing = true;
circData.Spacing = 60;  // 60 degree spacing
circData.TotalInstances = 6;
circData.Direction2 = true;
circData.EqualSpacing2 = true;
circData.Spacing2 = 45;
circData.TotalInstances2 = 3;

// Create the feature
