varyOpts.D1SpacingIncrement = 5;  // Additional 5 degrees per instance
varyOpts.D2SpacingIncrement = 2;

// Modify specific instance spacing
varyOpts.ModifyD1SpacingValue(2, 75);  // Instance 2 has 75 degree spacing
varyOpts.ModifyD2SpacingValue(2, 50);  // Instance 2 has 50 spacing in Direction 2

