// Example: Create a parting line draft on a box-shaped part
using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

ModelDoc2 swModel = swApp.ActiveDoc;
IFeatureManager featureMgr = swModel.FeatureManager;
IModelDocExtension swDocExt = (IModelDocExtension)swModel.Extension;
SelectionMgr selMgr = swModel.SelectionManager;

// Make pre-selections:
// Select parting line (edge) with mark 1
swDocExt.SelectByID2("Edge1", "EDGE", 0, 0, 0, false, 1, null, 0);

// Select faces to draft with mark 2
swDocExt.SelectByID2("Face1", "FACE", 0, 0, 0, true, 2, null, 0);
swDocExt.SelectByID2("Face2", "FACE", 0, 0, 0, true, 2, null, 0);

// Create parting line draft
double draftAngle = 5.0 * Math.PI / 180.0;  // 5 degrees in radians
Feature feature = featureMgr.InsertMultiFaceDraft(
    draftAngle,                               // Angle in radians
    false,                                    // Don't flip direction
    false,                                    // Face draft (not edge draft)
    (int)swDraftFacePropagationType_e.swFacePropNone,  // No propagation
    false,                                    // Not step draft
    false                                     // Not body draft
);

// Access and verify the created draft feature
IDraftFeatureData2 draftData = (IDraftFeatureData2)feature.GetDefinition();
Debug.Print($"Draft Type: {draftData.Type}");  // Should be 1 (swPartingLineDraft)
Debug.Print($"Draft Angle: {draftData.Angle} radians");
int partingLineCount = draftData.GetPartingLinesCount();
Debug.Print($"Parting Lines: {partingLineCount}");
