// Example 1: Create boss loft with feature scope affecting selected bodies only
public void CreateBossLoftWithFeatureScope(IFeatureManager fm, ModelDoc2 doc, object[] bodyArray)
{
    // Precondition: Profiles and guide curves already selected via SelectByID2 with marks:
    // - Mark 1: Profile sketches (Sketch1, Sketch2)
    // - Mark 2 (x4): Guide curves (Curve1-Curve4) for smooth transitions
    // - Mark 4: Centerline (Curve5)

    // Create the loft feature with UseFeatScope=true to restrict to selected bodies
    IFeature loftFeat = fm.InsertProtrusionBlend2(
        false,  // Closed
        true,   // KeepTangency
        false,  // ForceNonRational
        1.0,    // TessToleranceFactor
        0,      // StartMatchingType
        0,      // EndMatchingType
        1.0,    // StartTangentLength
        1.0,    // EndTangentLength
        true,   // StartTangentDir
        true,   // EndTangentDir
        false,  // IsThinBody
        0,      // Thickness1
        0,      // Thickness2
        0,      // ThinType
        true,   // Merge - merges in multibody context
        true,   // UseFeatScope - KEY: enables feature scope
        false,  // UseAutoSelect - false to specify which bodies
        (int)swGuideCurveInfluence_e.swGuideCurveInfluenceNextEdge
    );

    // Access and configure feature scope
    ILoftFeatureData loftData = (ILoftFeatureData)loftFeat.GetDefinition();
    loftData.FeatureScope = true;           // Ensure feature scope is enabled
    loftData.FeatureScopeBodies = bodyArray; // Specify which solid bodies to affect
}

// Example 2: Configure loft with guide curve influence
public void ConfigureGuideCurveInfluence(ILoftFeatureData loftData)
{
    // Set guide curve influence type
    loftData.GuideCurveInfluence = (int)swGuideCurveInfluence_e.swGuideCurveInfluenceNextEdge;

    // Enable tangency maintenance
    loftData.MaintainTangency = true;
    loftData.StartTangencyType = 1;  // 1 = tangent to normal
    loftData.EndTangencyType = 1;
}

