```csharp
// Example: Create a single-ended hole with offset-from-surface end condition
ModelDoc2 model = swApp.ActiveDoc as ModelDoc2;
SelectionMgr selMgr = model.SelectionManager as SelectionMgr;
FeatureManager featureMgr = model.FeatureManager as FeatureManager;

// Get the surface to offset from (must be selected before calling this)
Face2 offsetSurface = selMgr.GetSelectedObject6(1, -1) as Face2;

// Create the simple hole with offset-from-surface end condition
Feature holeFeat = featureMgr.SimpleHole2(
    0.001,  // 1mm diameter
    true,   // single-ended
    false, false,
    (int)swEndConditions_e.swEndCondOffsetFromSurface,  // offset-from-surface type
    0,
    0.001,  // ignored for offset-from-surface
    0,
    false, false, false, false, 0, 0,
    false,  // offset direction: false = toward sketch
    false,
    false,  // translate surface: false = true offset
    false,
    true, true, false, false, false
);

// Alternatively, using the feature data interface to set end condition reference:
ISimpleHoleFeatureData2 holeData = holeFeat.GetDefinition() as ISimpleHoleFeatureData2;
holeData.AccessSelections(model, null);

// Set the end condition type
holeData.Type = (int)swEndConditions_e.swEndCondOffsetFromSurface;

// Set the reference surface for the offset
holeData.SetEndConditionReference(offsetSurface);

// Set the offset distance (0.005 meters = 5mm)
holeData.SurfaceOffset = 0.005;

// Control offset direction: true = away from sketch, false = toward sketch
holeData.ReverseOffset = false;

// Use true offset: false means standard offset from surface
holeData.TranslateSurface = false;

// Apply the changes
holeFeat.ModifyDefinition(holeData, model, null);
holeData.ReleaseSelectionAccess();
```

