// Check plane type - CRITICAL: must determine type before modifying
int planeType2 = refPlaneData.Type2;  // swRefPlaneType_e: returns 11 for constraint-based
if (planeType2 == (int)swRefPlaneType_e.swRefPlaneConstraintBase)
{
    // For constraint-based planes (SOLIDWORKS 2010+), check Type for angle vs distance
    int planeType = refPlaneData.Type;  // swRefPlaneType_e: 7=swRefPlaneAngle, 5=swRefPlaneDistance

    // Modify properties - only valid properties for plane type:

    // For ANGLE constraint-based planes (Type == 7):
    // - Angle: System.double in radians (get/set)
    refPlaneData.Angle = 0.7853981633975;  // radians

    // For DISTANCE constraint-based planes (Type == 5):
    // - Distance: System.double in meters (get/set)
    refPlaneData.Distance = 0.1;  // meters

    // For any constraint-based plane, indexed properties use swRefPlaneReferenceIndex_e:
    // - Constraint(index): System.int with swRefPlaneReferenceConstraints_e values
    //   Valid values: 1=Parallel, 2=Perpendicular, 4=Coincident, 8=Distance, 16=Angle, 32=Tangent, 64=Project, etc.
    refPlaneData.Constraint[0] = (int)swRefPlaneReferenceConstraints_e.swRefPlaneReferenceConstraint_Parallel;

    // - AngleOrDistance(index): System.double (angle in radians OR distance in meters)
    refPlaneData.AngleOrDistance[0] = 0.0;

    // - Reference(index): System.Object (geometric entity: face, plane, edge, vertex, etc.)
    // Must use IEntity::Select4 or IModelDocExtension::SelectByID2/SelectByRay first
    refPlaneData.Reference[0] = selectedFace;  // or plane, edge, vertex, sketch point

    // - ReversedReferenceDirection(index): System.bool to flip normal direction
    refPlaneData.ReversedReferenceDirection[0] = false;
}
else
{
    // For non-constraint-based planes (SOLIDWORKS 2009 or earlier)
    // - AngleOrDistance: System.double only
    refPlaneData.AngleOrDistance[0] = 0.1;  // distance in meters
