// Example 1: Bidirectional Swept-Boss with constant twist angles
private void CreateBidirectionalSweep()
{
    // ... create/open model with sketch profile and path ...

    // Select profile sketch (e.g., ellipse), then path sketch (e.g., line)
    modelExtension.SelectByID2("Sketch1", "SKETCH", 0, 0, 0, false, 1, null, 0);
    modelExtension.SelectByID2("Sketch2", "SKETCH", 0, 0, 0, true, 4, null, 0);

    ISweepFeatureData sweep = (ISweepFeatureData)featureManager.CreateDefinition(
        (int)swFeatureNameID_e.swFmSweep);

    // Configure bidirectional sweep with different twist angles
    sweep.Direction = (int)swSweepDirection_e.swSweepBidirectional; // 1
    sweep.TwistControlType = (short)swTwistControlType_e.swTwistControlConstantTwistAlongPath; // 8
    sweep.PathAlignmentType = (int)swTangencyType_e.swTangencyNone; // 0

    // Twist in Direction 1: 31.12217 radians
    sweep.SetTwistAngle(31.12217);
    sweep.D1ReverseTwistDir = false;

    // Twist in Direction 2: 12.139 radians (different from Direction 1)
    sweep.SetD2TwistAngle(12.139);
    sweep.D2ReverseTwistDir = true; // Reverse twist in Direction 2

    // Standard settings
    sweep.TangentPropagation = false;
    sweep.AlignWithEndFaces = false;
    sweep.MaintainTangency = false;
    sweep.AdvancedSmoothing = false;
    sweep.ThinFeature = false;
    sweep.SetWallThickness(true, 0.0);
    sweep.SetWallThickness(false, 0.0);
    sweep.Merge = true;
    sweep.FeatureScope = true;
    sweep.AutoSelect = true;
    sweep.MergeSmoothFaces = true;
    sweep.CircularProfile = false;

    IFeature sweptFeature = featureManager.CreateFeature(sweep);
    Debug.WriteLine("Bidirectional Swept-Boss created: " + sweptFeature.Name);
}

// Example 2: Bidirectional Swept-Cut with guide curves and path alignment
private void CreateBidirectionalSweepCut()
{
    // ... select profile, path, and guide curve ...
    // modelExtension.SelectByID2("ProfileSketch", "SKETCH", ..., false, 1, null, 0);
    // modelExtension.SelectByID2("PathSketch", "SKETCH", ..., true, 4, null, 0);
    // modelExtension.SelectByID2("GuideSketch", "SKETCH", ..., true, 2, null, 0);

    ISweepFeatureData sweep = (ISweepFeatureData)featureManager.CreateDefinition(
        (int)swFeatureNameID_e.swFmSweepCut);

    // Bidirectional sweep configuration
    sweep.Direction = (int)swSweepDirection_e.swSweepBidirectional; // 1
    sweep.TwistControlType = (short)swTwistControlType_e.swTwistControlFollowPath; // 0
    sweep.PathAlignmentType = (int)swTangencyType_e.swTangencyNone; // 0

    // No specific twist angles needed when using swTwistControlFollowPath
    sweep.TangentPropagation = false;
    sweep.AlignWithEndFaces = false;
    sweep.MaintainTangency = false;
    sweep.MergeSmoothFaces = true; // Important when using guide curves
    sweep.AdvancedSmoothing = false;
    sweep.CircularProfile = false;
    sweep.Merge = true;
    sweep.FeatureScope = true;
    sweep.AutoSelect = true;

    IFeature sweptCut = featureManager.CreateFeature(sweep);

    // Access and verify feature properties
    sweep = (ISweepFeatureData)sweptCut.GetDefinition();
    sweep.AccessSelections(model, null);

    IFeature pathFeat = sweep.Path;
    IFeature profFeat = sweep.Profile;

    Debug.WriteLine("Path: " + pathFeat.Name + ", Profile: " + profFeat.Name);
    Debug.WriteLine("Path Type: " + sweep.GetPathType());
    Debug.WriteLine("Profile Type: " + sweep.GetProfileType());
    Debug.WriteLine("Num Guide Curves: " + sweep.GetGuideCurvesCount());

    sweep.ReleaseSelectionAccess();
}

// Example 3: Query bidirectional sweep parameters
private void QueryBidirectionalSweep(IFeature sweptFeature)
{
    ISweepFeatureData sweep = (ISweepFeatureData)sweptFeature.GetDefinition();
    sweep.AccessSelections(model, null);

    // Get direction information
    int direction = sweep.Direction;
    bool isBidirectional = (direction == (int)swSweepDirection_e.swSweepBidirectional);

    // Get twist angles for both directions
    double twistD1 = sweep.GetTwistAngle(); // Direction 1
    double twistD2 = sweep.GetD2TwistAngle(); // Direction 2
    bool reverseD1 = sweep.D1ReverseTwistDir;
    bool reverseD2 = sweep.D2ReverseTwistDir;

    Debug.WriteLine("Bidirectional: " + isBidirectional);
    Debug.WriteLine("Direction 1 Twist: " + twistD1 + " rad, Reverse: " + reverseD1);
    Debug.WriteLine("Direction 2 Twist: " + twistD2 + " rad, Reverse: " + reverseD2);
    Debug.WriteLine("Twist Control: " + sweep.TwistControlType);
    Debug.WriteLine("Path Alignment: " + sweep.PathAlignmentType);

    sweep.ReleaseSelectionAccess();
}
