// Example: Create a constant radius fillet with corner rounding
using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

// ... model loaded, active doc available ...
SldWorks swApp = ..;
ModelDoc2 swModel = swApp.ActiveDoc;
FeatureManager swFeatMgr = swModel.FeatureManager;
ModelDocExtension swModelDocExt = swModel.Extension;

// Create the fillet feature data object
object featDataObj = swFeatMgr.CreateDefinition(swFmFillet);
ISimpleFilletFeatureData2 filletData = (ISimpleFilletFeatureData2)featDataObj;

// Initialize as constant radius fillet
filletData.Initialize((int)swSimpleFilletType_e.swConstRadiusFillet);

// Set the cross-sectional profile to circular
filletData.ConicTypeForCrossSectionProfile = (int)swFeatureFilletProfileType_e.swFeatureFilletCircular;

// Configure overflow behavior
filletData.OverflowType = (int)swFilletOverFlowType_e.swFilletOverFlowType_Default;

// Set fillet radius
filletData.DefaultRadius = 0.01;

// Enable corner rounding for adjacent edges
filletData.RoundCorners = true;

// Select the edges to fillet using SelectByID2 with Mark=1
bool status = swModelDocExt.SelectByID2("Edge@Box1", "EDGE", 0, 0, 0, false, 1, null, 0);
status = swModelDocExt.SelectByID2("Edge@Box2", "EDGE", 0, 0, 0, true, 1, null, 0);

// Create the fillet feature
Feature swFeat = swFeatMgr.CreateFeature(filletData);
