// Complete example: Create a swept-cut feature using a tool body

// Assume: swModel has a target solid body (to be cut) and a tool body (revolve feature) and a sketch (path)

// Step 1: Make selections in order:
// - Tool body (the solid to sweep along the path for cutting)
// - Sweep path (sketch defining the path)
// - Target body (the solid to be cut)
model.ClearSelection2(true);
bool ok = modelExtension.SelectByID2("Revolve1", "SOLIDBODY", 0, 0, 0, false, 1, null, 0);
ok = modelExtension.SelectByID2("Sketch2", "SKETCH", 0, 0, 0, true, 4, null, 0);
