string size = "#97";
short endType = (int)swEndConditions_e.swEndCondBlind;

// Conversion factors
double convLength = 25.4 / 1000;  // inches to meters
double convAngle = (22.0 / 7.0) / 180.0;  // degrees to radians

// Slot parameters
double diameter = 0.5 * convLength;   // 0.5 inches
double depth = 2.0 * convLength;      // 2 inches deep
